        ticks: { color: '#555', font: { family: "'IBM Plex Mono', monospace", size: 9 }, maxTicksLimit: 6 },
        title: { display: true, text: y1Label, color: '#3a3a3a', font: { family: "'IBM Plex Mono', monospace", size: 9 } },
        border: { color: '#1e1e1e' }
